/**
 * LegalEntityList Component
 *
 * Renders a paginated, sortable list of legal_entities with search,
 * filtering, and export capabilities.
 */
export function LegalEntityList({
  title = 'LegalEntities',
  showAddButton = true,
  onAdd,
  exportable = true,
  emptyMessage = 'No legal_entities found',
  navigateOnClick = true,
  onRowClick,
  onDelete,
  additionalFilters = {},
  className = '',
}: LegalEntityListProps): React.ReactElement {
  const navigate = useNavigate();
  const { showSuccess, showError } = useNotification();
  const deleteLegalEntityMutation = useDeleteLegalEntity();

  // -------------------------------------------------------------------------
  // State
  // -------------------------------------------------------------------------

  // Pagination state
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(DEFAULT_ROWS_PER_PAGE);

  // Search state with debounce
  const [searchInput, setSearchInput] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');

  // Sorting state
  const [sortKey, setSortKey] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc');

  // -------------------------------------------------------------------------
  // Effects
  // -------------------------------------------------------------------------

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchInput);
      setPage(0); // Reset to first page on search
    }, SEARCH_DEBOUNCE_MS);

    return () => clearTimeout(timer);
  }, [searchInput]);

  // -------------------------------------------------------------------------
  // Data Fetching
  // -------------------------------------------------------------------------

  // Build filter options
  const filters: LegalEntityFilterOptions = useMemo(
    () => ({
      search: debouncedSearch || undefined,
      page: page + 1, // API uses 1-indexed pages
      page_size: rowsPerPage,
      sort_by: sortKey || undefined,
      sort_order: sortKey ? sortDirection : undefined,
      ...additionalFilters,
    }),
    [debouncedSearch, page, rowsPerPage, sortKey, sortDirection, additionalFilters]
  );

  // Fetch data using React Query
  const {
    data: legalEntities,
    isLoading,
    isError,
    error,
    refetch,
  } = useLegalEntities({ filters, activeOnly: false });

  // -------------------------------------------------------------------------
  // Handlers
  // -------------------------------------------------------------------------

  /** Handle page change */
  const handleChangePage = useCallback(
    (_event: unknown, newPage: number) => {
      setPage(newPage);
    },
    []
  );

  /** Handle rows per page change */
  const handleChangeRowsPerPage = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      setRowsPerPage(parseInt(event.target.value, 10));
      setPage(0);
    },
    []
  );

  /** Handle sort change */
  const handleSort = useCallback((columnKey: string) => {
    setSortKey((prevKey) => {
      if (prevKey === columnKey) {
        setSortDirection((prevDir) => (prevDir === 'asc' ? 'desc' : 'asc'));
        return columnKey;
      }
      setSortDirection('asc');
      return columnKey;
    });
  }, []);

  /** Handle row click */
  const handleRowClick = useCallback(
    (row: LegalEntity) => {
      if (onRowClick) {
        onRowClick(row);
      } else if (navigateOnClick) {
        navigate(`/legal_entities/${row.id}`);
      }
    },
    [navigate, navigateOnClick, onRowClick]
  );

  /** Handle export click */
  const handleExport = useCallback(() => {
    if (legalEntities && legalEntities.length > 0) {
      const timestamp = new Date().toISOString().split('T')[0];
      exportToCsv(legalEntities, `legal_entities_${timestamp}`);
    }
  }, [legalEntities]);

  /** Handle add click */
  const handleAdd = useCallback(() => {
    if (onAdd) {
      onAdd();
    } else {
      navigate('/legal_entities/new');
    }
  }, [navigate, onAdd]);

  /** Handle edit click */
  const handleEdit = useCallback(
    (row: LegalEntity, event: React.MouseEvent) => {
      event.stopPropagation(); // Prevent row click navigation
      navigate(`/legal_entities/${row.id}/edit`);
    },
    [navigate]
  );

  /** Handle view click */
  const handleView = useCallback(
    (row: LegalEntity, event: React.MouseEvent) => {
      event.stopPropagation(); // Prevent row click navigation
      navigate(`/legal_entities/${row.id}`);
    },
    [navigate]
  );

  /** Handle delete click */
  const handleDelete = useCallback(
    async (row: LegalEntity, event: React.MouseEvent) => {
      event.stopPropagation(); // Prevent row click navigation

      // Delegate to external handler if provided
      if (onDelete) {
        onDelete(row);
        return;
      }

      // Confirm before deleting
      if (!window.confirm(`Are you sure you want to delete this legal_entity?`)) {
        return;
      }

      try {
        await deleteLegalEntityMutation.mutateAsync(row.id);
        showSuccess('LegalEntity deleted successfully');
        refetch(); // Refresh the list after deletion
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'An unexpected error occurred';
        showError(`Failed to delete LegalEntity: ${errorMessage}`);
      }
    },
    [onDelete, deleteLegalEntityMutation, showSuccess, showError, refetch]
  );

  /** Handle refresh click */
  const handleRefresh = useCallback(() => {
    refetch();
  }, [refetch]);

  // -------------------------------------------------------------------------
  // Render Helpers
  // -------------------------------------------------------------------------

  /** Render loading skeleton */
  const renderSkeleton = () => (
    <>
      {Array.from({ length: SKELETON_ROWS }).map((_, index) => (
        <TableRow key={index}>
          {COLUMNS.map((column) => (
            <TableCell key={String(column.key)}>
              <Skeleton animation="wave" height={24} />
            </TableCell>
          ))}
          {/* Actions column skeleton */}
          <TableCell>
            <Skeleton animation="wave" width={32} height={32} variant="circular" />
          </TableCell>
        </TableRow>
      ))}
    </>
  );

  /** Render empty state */
  const renderEmptyState = () => (
    <TableRow>
      <TableCell colSpan={COLUMNS.length + 1} align="center">
        <Box py={4}>
          <Typography color="text.secondary">{emptyMessage}</Typography>
        </Box>
      </TableCell>
    </TableRow>
  );

  /** Render data rows */
  const renderRows = () => (
    <>
      {legalEntities?.map((row) => (
        <TableRow
          key={row.id}
          hover
          onClick={() => handleRowClick(row)}
          sx={{
            cursor: navigateOnClick || onRowClick ? 'pointer' : 'default',
          }}
        >
          {COLUMNS.map((column) => {
            const value = row[column.key as keyof LegalEntity];
            return (
              <TableCell key={String(column.key)} align={column.align || 'left'}>
                {column.render ? column.render(value, row) : String(value ?? '-')}
              </TableCell>
            );
          })}
          {/* Actions cell */}
          <TableCell align="right">
            <Tooltip title="View LegalEntity">
              <span>
                <IconButton
                  size="small"
                  data-testid={`btn-view-legal_entity-${row.id}`}
                  onClick={(e) => handleView(row, e)}
                >
                  <ViewIcon fontSize="small" />
                </IconButton>
              </span>
            </Tooltip>
            <Tooltip title="Edit LegalEntity">
              <IconButton
                size="small"
                data-testid={`btn-edit-legal_entity-${row.id}`}
                onClick={(e) => handleEdit(row, e)}
              >
                <EditIcon fontSize="small" />
              </IconButton>
            </Tooltip>
            <Tooltip title="Delete LegalEntity">
              <span>
                <IconButton
                  size="small"
                  data-testid={`btn-delete-legal_entity-${row.id}`}
                  onClick={(e) => handleDelete(row, e)}
                >
                  <DeleteIcon fontSize="small" />
                </IconButton>
              </span>
            </Tooltip>
          </TableCell>
        </TableRow>
      ))}
    </>
  );

  // -------------------------------------------------------------------------
  // Error State
  // -------------------------------------------------------------------------

  if (isError) {
    return (
      <Box className={className} p={3}>
        <MuiAlert
          severity="error"
          action={
            <IconButton color="inherit" size="small" onClick={handleRefresh}>
              <RefreshIcon />
            </IconButton>
          }
        >
          Error loading legal_entities: {(error as Error)?.message || 'Unknown error'}
        </MuiAlert>
      </Box>
    );
  }

  // -------------------------------------------------------------------------
  // Main Render
  // -------------------------------------------------------------------------

  return (
    <Box className={className}>
      {/* Header */}
      <Box
        display="flex"
        justifyContent="space-between"
        alignItems="center"
        mb={3}
      >
        <Typography variant="h5" component="h1">
          {title}
        </Typography>

        <Box display="flex" gap={1}>
          <Tooltip title="Refresh">
            <span>
              <IconButton onClick={handleRefresh} disabled={isLoading}>
                <RefreshIcon />
              </IconButton>
            </span>
          </Tooltip>

          {exportable && (
            <Tooltip title="Export to CSV">
              <span>
                <IconButton
                  onClick={handleExport}
                  disabled={isLoading || !legalEntities?.length}
                >
                  <DownloadIcon />
                </IconButton>
              </span>
            </Tooltip>
          )}

          {showAddButton && (
            <Tooltip title="Add LegalEntity">
              <IconButton
                onClick={handleAdd}
                color="primary"
                data-testid="btn-add-legal_entity"
              >
                <AddIcon />
              </IconButton>
            </Tooltip>
          )}
        </Box>
      </Box>

      {/* Search Filter */}
      <Box mb={2}>
        <TextField
          fullWidth
          size="small"
          placeholder="Search legal_entities..."
          value={searchInput}
          onChange={(e) => setSearchInput(e.target.value)}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <SearchIcon color="action" />
              </InputAdornment>
            ),
          }}
        />
      </Box>

      {/* Table */}
      <Paper>
        <TableContainer>
          <Table size="small">
            <TableHead>
              <TableRow>
                {COLUMNS.map((column) => (
                  <TableCell
                    key={String(column.key)}
                    align={column.align || 'left'}
                    sx={{ width: column.width }}
                  >
                    {column.sortable ? (
                      <TableSortLabel
                        active={sortKey === column.key}
                        direction={sortKey === column.key ? sortDirection : 'asc'}
                        onClick={() => handleSort(String(column.key))}
                      >
                        {column.label}
                      </TableSortLabel>
                    ) : (
                      column.label
                    )}
                  </TableCell>
                ))}
                {/* Actions column header */}
                <TableCell align="right" sx={{ width: '120px' }}>
                  Actions
                </TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {isLoading
                ? renderSkeleton()
                : legalEntities?.length
                  ? renderRows()
                  : renderEmptyState()}
            </TableBody>
          </Table>
        </TableContainer>

        {/* Pagination */}
        <TablePagination
          component="div"
          count={legalEntities?.length || 0}
          page={page}
          onPageChange={handleChangePage}
          rowsPerPage={rowsPerPage}
          onRowsPerPageChange={handleChangeRowsPerPage}
          rowsPerPageOptions={ROWS_PER_PAGE_OPTIONS}
        />
      </Paper>
    </Box>
  );
}

// Default export for convenience
export default LegalEntityList;
